`timescale 1 ns / 1 ns

module Synchronous_Delay
          (  input logic clk,
             input logic reset,
             input logic enb,
             input logic u,
             input logic E,
             output logic y);


  logic Delay_out1;


  always_ff @(posedge clk)
    begin : Delay_process
      if (reset == 1'b1) begin
        Delay_out1 <= 1'b0;
      end
      else begin
        if (enb && E) begin
          Delay_out1 <= u;
        end
      end
    end

  assign y = Delay_out1;

endmodule  // Synchronous_Delay

